import axios from "axios";
import { parseStringPromise } from "xml2js";

// Import bookmarks from a remote XML feed. Previously used the deprecated
// `request` library, which pulled in unpatched transitive dependencies
// (form-data, qs, tough-cookie) with no fixed versions available; replaced
// with axios, already a dependency elsewhere in this app.
export async function fetchXml(url) {
  const res = await axios.get(url, { validateStatus: () => true });
  if (res.status >= 400) {
    throw new Error(`upstream ${res.status}`);
  }
  return typeof res.data === "string" ? res.data : JSON.stringify(res.data);
}

